function sumUniqueEvenNumbers(numbers) {
  // Create an empty object to store the unique even numbers
  let uniqueEvens = {};

  // Initialize the sum to 0
  let sum = 0;

  // Loop through each number in the array
  for (let i = 0; i < numbers.length; i++) {
    // Check if the number is even and not already in the uniqueEvens object
    if (numbers[i] % 2 === 0 && !uniqueEvens[numbers[i]]) {
      // Add the number to the uniqueEvens object
      uniqueEvens[numbers[i]] = true;
      // Add the number to the sum
      sum += numbers[i];
    }
  }

  // Return the sum
  return sum;
}
```

