```javascript
function mostFrequentCharacter(string) {
  // Convert string to lowercase
  string = string.toLowerCase();

  // Create a frequency object to store character counts
  const frequency = {};

  // Loop through each character in the string
  for (let i = 0; i < string.length; i++) {
    const char = string[i];

    // Skip if character is a space or special character
    if (/\W|_|\d/g.test(char)) continue;

    // If character is already in the frequency object, increment its count
    if (frequency[char]) {
      frequency[char]++;
    } else {
      // Otherwise, add character to the frequency object with a count of 1
      frequency[char] = 1;
    }
  }

  // Find the character with the highest frequency
  let mostFrequentChar = "";
  let highestFrequency = 0;

  for (const char in frequency) {
    if (frequency[char] > highestFrequency) {
      mostFrequentChar = char;
      highestFrequency = frequency[char];
    }
  }

  return mostFrequentChar;
}
```

