import java.util.Scanner;

public class FibonacciSequence {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter the number of Fibonacci numbers to generate: ");
        int n = scanner.nextInt();

        System.out.print("Fibonacci Sequence up to " + n + " numbers: ");
        generateFibonacciSequence(n);
    }

    public static void generateFibonacciSequence(int n) {
        if (n < 1) {
            System.out.println("Invalid input! Please enter a positive integer greater than 1.");
            return;
        }

        if (n == 1) {
            System.out.println("0");
            return;
        }

        System.out.print("0, 1");
        int a = 0;
        int b = 1;
        for (int i = 2; i < n; i++) {
            int temp = a + b;
            System.out.print(", " + temp);
            a = b;
            b = temp;
        }
        System.out.println();
    }
}

