```cpp
#include <iostream>
#include <climits>

int findMax(int arr[], int start, int end) {
    if (start > end) {
        // Array is empty, return special value
        return INT_MIN;
    }

    if (start == end) {
        // Only one element in the array, return it
        return arr[start];
    }

    int mid = (start + end) / 2;
    int maxLeft = findMax(arr, start, mid);
    int maxRight = findMax(arr, mid + 1, end);

    return std::max(maxLeft, maxRight);
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int size = sizeof(arr) / sizeof(arr[0]);
    int max = findMax(arr, 0, size - 1);
    std::cout << "Maximum element: " << max << std::endl;

    return 0;
}
```

