  // Return [0, 1] for n = 2
  if (n === 2) {
    return [0, 1];
  }

  // Check if Fibonacci numbers for n are already calculated and cached
  if (fibonacciCache[n]) {
    return fibonacciCache[n];
  }

  // Calculate Fibonacci numbers
  let fibonacciNumbers = [0, 1];

  for (let i = 2; i < n; i++) {
    let fib = fibonacciNumbers[i-1] + fibonacciNumbers[i-2];
    fibonacciNumbers.push(fib);
  }

  // Reverse the Fibonacci numbers and store them in cache
  fibonacciNumbers.reverse();
  fibonacciCache[n] = fibonacciNumbers;

  return fibonacciNumbers;
}

