public class PrimeFactorsSum {

    // Function to check if a number is prime
    static boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }

    // Function to calculate the sum of prime factors
    static long sumOfPrimeFactors(int num) {
        long sum = 0;
        for (int i = 2; i <= num; i++) {
            if (num % i == 0 && isPrime(i)) {
                sum += i;
            }
        }
        return sum;
    }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        System.out.print("Enter the first positive prime number: ");
        int num1 = input.nextInt();
        System.out.print("Enter the second positive prime number: ");
        int num2 = input.nextInt();

        if (!isPrime(num1) || !isPrime(num2)) {
            System.out.println("Input numbers are not prime. Program terminated.");
            System.exit(0);
        }

        long sum = sumOfPrimeFactors(num1) + sumOfPrimeFactors(num2);

        if (sum > Math.pow(10, 12)) {
            System.out.println("Sum of prime factors exceeds 10^12.");
        } else {
            System.out.println("Sum of prime factors: " + sum);
        }
    }
}

def count_characters(string, threshold=1):
    counts = {}
    vowels = ['a', 'e', 'i', 'o', 'u']

    # Convert string to lowercase
    string = string.lower()

    # Loop through each character in the string
    for char in string:
        # Check if character is alphabetical and not a vowel
        if char.isalpha() and char not in vowels:
            # Count the character
            if char in counts:
                counts[char] += 1
            else:
                counts[char] = 1

    # Sort the dictionary in descending order based on count
    sorted_counts = sorted(counts.items(), key=lambda x: x[1], reverse=True)

    # Filter out characters with count less than or equal to threshold
    filtered_counts = {char: count for char, count in sorted_counts if count > threshold}

    return filtered_counts

