class FruitColors:
    def __init__(self):
        self.fruits = {}
        self.color_fruits = {}
        self.max_colors = 0

    def add_fruit(self, fruit, colors):
        self.fruits[fruit] = colors
        for color in colors:
            if color not in self.color_fruits:
                self.color_fruits[color] = set()
            self.color_fruits[color].add(fruit)

            if len(self.color_fruits[color]) > self.max_colors:
                self.max_colors = len(self.color_fruits[color])

    def get_fruits_by_color(self, color):
        if color in self.color_fruits:
            return self.color_fruits[color]
        else:
            return set()

    def get_fruits_with_most_colors(self):
        max_color_fruits = []
        for fruit, colors in self.fruits.items():
            if len(colors) == self.max_colors:
                max_color_fruits.append(fruit)
        return max_color_fruits

