 */
public class RandomNumberGenerator {

    public static void main(String[] args) {

        // initialize scanner and random number generator
        Scanner input = new Scanner(System.in);
        Random rng = new Random();

        // prompt user for range
        System.out.print("Enter the minimum number in the range: ");
        int min = input.nextInt();
        System.out.print("Enter the maximum number in the range: ");
        int max = input.nextInt();

        // check for invalid input
        if (max <= min) {
            System.out.println("Error: Maximum must be greater than minimum!");
            return;
        }

        // generate and display random number
        int randomNumber = rng.nextInt(max - min + 1) + min;
        System.out.println("Your randomly generated number is: " + randomNumber);
    }
}

