fun calculateTriangleArea(a: Double, b: Double, c: Double): Double {
    // calculate the semi-perimeter
    val s = (a + b + c) / 2
    // calculate the area using Heron's formula
    val area = sqrt(s * (s - a) * (s - b) * (s - c))
    return area
}
```

